{
  "name": "SevaMed: AI Medical Bill & Prescription Explainer",
  "description": "An MVP for Indian patients to simplify complex medical documents, bills, and prescriptions using Gemini AI. Translates medical jargon into plain English/Hindi-context and flags unnecessary hospital charges.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum DocumentType {
  PRESCRIPTION = 'PRESCRIPTION',
  LAB_REPORT = 'LAB_REPORT',
  HOSPITAL_BILL = 'HOSPITAL_BILL',
  INSURANCE_REJECTION = 'INSURANCE_REJECTION',
  UNKNOWN = 'UNKNOWN'
}

export interface MedicalAnalysis {
  documentType: DocumentType;
  summary: string;
  simplifiedTerms: {
    jargon: string;
    meaning: string;
    importance: string;
  }[];
  criticalFindings: {
    issue: string;
    description: string;
    action: string;
  }[];
  billAnalysis?: {
    totalAmount: string;
    potentialOvercharges: {
      item: string;
      reason: string;
      suggestedAction: string;
    }[];
  };
  insuranceInsights?: {
    rejectionReason?: string;
    appealAdvice?: string;
  };
  nextSteps: string[];
}

export interface AnalysisState {
  file: File | null;
  preview: string | null;
  isAnalyzing: boolean;
  result: MedicalAnalysis | null;
  error: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { DocumentType, MedicalAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    documentType: {
      type: Type.STRING,
      description: 'The type of medical document identified.',
    },
    summary: {
      type: Type.STRING,
      description: 'A brief, 2-sentence summary of the document content.',
    },
    simplifiedTerms: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          jargon: { type: Type.STRING },
          meaning: { type: Type.STRING },
          importance: { type: Type.STRING }
        },
        required: ['jargon', 'meaning', 'importance']
      }
    },
    criticalFindings: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          issue: { type: Type.STRING },
          description: { type: Type.STRING },
          action: { type: Type.STRING }
        },
        required: ['issue', 'description', 'action']
      }
    },
    billAnalysis: {
      type: Type.OBJECT,
      properties: {
        totalAmount: { type: Type.STRING },
        potentialOvercharges: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              item: { type: Type.STRING },
              reason: { type: Type.STRING },
              suggestedAction: { type: Type.STRING }
            }
          }
        }
      }
    },
    insuranceInsights: {
      type: Type.OBJECT,
      properties: {
        rejectionReason: { type: Type.STRING },
        appealAdvice: { type: Type.STRING }
      }
    },
    nextSteps: {
      type: Type.ARRAY,
      items: { type: Type.STRING }
    }
  },
  required: ['documentType', 'summary', 'simplifiedTerms', 'criticalFindings', 'nextSteps']
};

export const analyzeMedicalDocument = async (
  base64Data: string,
  mimeType: string
): Promise<MedicalAnalysis> => {
  const model = ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Data,
            mimeType: mimeType
          }
        },
        {
          text: `You are a helpful, expert medical consultant in India specialized in simplifying complex healthcare documents for patients. 
          Your goal is to analyze the attached document (Prescription, Lab Report, Bill, or Insurance Rejection).

          Specific Context for India:
          1. Use Indian numbering (Lakhs/Crores if applicable).
          2. Reference common Indian medical practices (e.g., TPAs, CGHS, Ayushman Bharat if hinted).
          3. For prescriptions, explain medicine names and common dosing abbreviations (BD, TDS, OD).
          4. For lab reports, identify abnormal ranges.
          5. For bills, highlight common overcharges like excessive "Pharmacy Charges" or "Consumables" not covered by standard insurance.
          6. Translate complex medical jargon into simple, comforting English that a layperson in India would understand.

          Respond ONLY in JSON format following the provided schema.`
        }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: ANALYSIS_SCHEMA as any,
    }
  });

  const response = await model;
  const resultText = response.text;
  if (!resultText) {
    throw new Error("Model failed to generate a response.");
  }

  return JSON.parse(resultText) as MedicalAnalysis;
};

import React, { useRef } from 'react';
import { Upload, Camera, FileText, X } from 'lucide-react';

interface FileUploaderProps {
  onFileSelect: (file: File) => void;
  selectedFile: File | null;
  onClear: () => void;
}

export const FileUploader: React.FC<FileUploaderProps> = ({ onFileSelect, selectedFile, onClear }) => {
  const inputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onFileSelect(e.target.files[0]);
    }
  };

  return (
    <div className="w-full max-w-xl mx-auto">
      {!selectedFile ? (
        <div 
          onClick={() => inputRef.current?.click()}
          className="border-2 border-dashed border-slate-300 rounded-2xl p-10 flex flex-col items-center justify-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group"
        >
          <input
            type="file"
            className="hidden"
            ref={inputRef}
            onChange={handleFileChange}
            accept="image/*,application/pdf"
          />
          <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
            <Upload className="w-8 h-8 text-blue-600" />
          </div>
          <h3 className="text-lg font-semibold text-slate-800">Upload medical document</h3>
          <p className="text-slate-500 text-center mt-2 text-sm">
            Take a photo of a prescription, lab report, or hospital bill.<br/>
            Supports PDF and Images.
          </p>
          <div className="flex space-x-4 mt-6">
            <button className="flex items-center space-x-2 px-4 py-2 bg-slate-100 rounded-lg text-sm font-medium text-slate-700 hover:bg-slate-200">
              <Camera className="w-4 h-4" />
              <span>Camera</span>
            </button>
            <button className="flex items-center space-x-2 px-4 py-2 bg-slate-100 rounded-lg text-sm font-medium text-slate-700 hover:bg-slate-200">
              <FileText className="w-4 h-4" />
              <span>Browse Files</span>
            </button>
          </div>
        </div>
      ) : (
        <div className="relative bg-white border border-slate-200 rounded-2xl p-4 flex items-center shadow-sm">
          <div className="w-12 h-12 bg-blue-50 rounded-lg flex items-center justify-center mr-4">
            <FileText className="w-6 h-6 text-blue-600" />
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-sm font-medium text-slate-900 truncate">{selectedFile.name}</p>
            <p className="text-xs text-slate-500">{(selectedFile.size / (1024 * 1024)).toFixed(2)} MB</p>
          </div>
          <button 
            onClick={onClear}
            className="p-2 text-slate-400 hover:text-red-500 transition-colors"
          >
            <X className="w-5 h-5" />
          </button>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { 
  Stethoscope, 
  AlertCircle, 
  IndianRupee, 
  ShieldCheck, 
  ArrowRight, 
