    switch(type) {
      case DocumentType.PRESCRIPTION: return 'bg-purple-100 text-purple-700';
      case DocumentType.HOSPITAL_BILL: return 'bg-amber-100 text-amber-700';
      case DocumentType.LAB_REPORT: return 'bg-emerald-100 text-emerald-700';
      default: return 'bg-blue-100 text-blue-700';
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Summary Header */}
      <div className="bg-white border border-slate-200 rounded-3xl p-6 shadow-sm">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-6">
          <div className="flex items-center space-x-3">
            <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${getDocTypeColor(analysis.documentType)}`}>
              {analysis.documentType.replace('_', ' ')}
            </span>
            <div className="flex items-center text-slate-400 text-sm">
              <CheckCircle2 className="w-4 h-4 text-emerald-500 mr-1" />
              AI Verified Analysis
            </div>
          </div>
          <button 
            onClick={() => window.print()}
            className="flex items-center justify-center space-x-2 px-4 py-2 border border-slate-200 rounded-xl text-sm font-medium text-slate-700 hover:bg-slate-50"
          >
            <Printer className="w-4 h-4" />
            <span>Save as PDF / Print</span>
          </button>
        </div>

        <h2 className="text-2xl font-bold text-slate-900 mb-2">Overview</h2>
        <p className="text-slate-600 leading-relaxed">{analysis.summary}</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Simplified Jargon */}
        <section className="bg-white border border-slate-200 rounded-3xl p-6 shadow-sm">
          <div className="flex items-center space-x-2 mb-6">
            <Stethoscope className="w-5 h-5 text-blue-600" />
            <h3 className="text-lg font-bold text-slate-800">Medical Terms Simplified</h3>
          </div>
          <div className="space-y-4">
            {analysis.simplifiedTerms.map((term, i) => (
              <div key={i} className="group p-4 rounded-2xl bg-slate-50 hover:bg-blue-50 transition-colors border border-transparent hover:border-blue-100">
                <div className="flex items-start justify-between">
                  <h4 className="font-bold text-slate-900">{term.jargon}</h4>
                  <Info className="w-4 h-4 text-slate-400 opacity-0 group-hover:opacity-100" />
                </div>
                <p className="text-sm text-slate-700 mt-1">{term.meaning}</p>
                <div className="mt-2 text-xs font-medium text-blue-600 bg-blue-100/50 inline-block px-2 py-0.5 rounded">
                  Why it matters: {term.importance}
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* Critical Findings / Flags */}
        <section className="bg-white border border-slate-200 rounded-3xl p-6 shadow-sm">
          <div className="flex items-center space-x-2 mb-6">
            <AlertCircle className="w-5 h-5 text-rose-600" />
            <h3 className="text-lg font-bold text-slate-800">Key Points & Flags</h3>
          </div>
          <div className="space-y-4">
            {analysis.criticalFindings.length > 0 ? analysis.criticalFindings.map((finding, i) => (
              <div key={i} className="p-4 rounded-2xl border border-rose-100 bg-rose-50">
                <h4 className="font-bold text-rose-900 flex items-center">
                  <span className="w-2 h-2 bg-rose-500 rounded-full mr-2"></span>
                  {finding.issue}
