              <p className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Potential Savings Detected</p>
              {analysis.billAnalysis.potentialOvercharges.map((charge, i) => (
                <div key={i} className="flex flex-col md:flex-row md:items-center justify-between p-4 rounded-2xl bg-amber-50 border border-amber-100 gap-4">
                  <div className="flex-1">
                    <h4 className="font-bold text-amber-900">{charge.item}</h4>
                    <p className="text-sm text-amber-800">{charge.reason}</p>
