          <div className="flex items-center space-x-2 mb-6">
            <ShieldCheck className="w-6 h-6 text-indigo-200" />
            <h3 className="text-xl font-bold">Insurance Claims Assistant</h3>
          </div>
          <div className="grid md:grid-cols-2 gap-8">
            <div className="space-y-2">
              <p className="text-indigo-200 text-sm font-medium uppercase">Rejection Context</p>
              <p className="text-lg leading-snug font-medium">
                {analysis.insuranceInsights.rejectionReason || "No rejection detected. Ensure all documents are submitted to TPA."}
              </p>
            </div>
            <div className="bg-white/10 backdrop-blur-md rounded-2xl p-6 border border-white/10">
              <p className="text-indigo-100 text-sm font-medium uppercase mb-2">Advice for Appeal</p>
              <p className="text-sm leading-relaxed opacity-90">
                {analysis.insuranceInsights.appealAdvice || "Prepare your policy copy and original hospital summaries for claim processing."}
              </p>
            </div>
          </div>
        </section>
      )}

      {/* Next Steps */}
      <section className="pb-10">
        <h3 className="text-xl font-bold text-slate-900 mb-6">What you should do next</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {analysis.nextSteps.map((step, i) => (
            <div key={i} className="flex items-center space-x-4 p-5 bg-white border border-slate-200 rounded-2xl shadow-sm hover:border-blue-300 transition-all">
              <div className="flex-shrink-0 w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center font-bold text-blue-600">
                {i + 1}
              </div>
              <p className="text-slate-700 font-medium">{step}</p>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { Layout } from './components/Layout';
import { FileUploader } from './components/FileUploader';
import { AnalysisView } from './components/AnalysisView';
import { analyzeMedicalDocument } from './services/geminiService';
import { AnalysisState } from './types';
import { Loader2, AlertCircle, FileText, CheckCircle, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [state, setState] = useState<AnalysisState>({
    file: null,
    preview: null,
    isAnalyzing: false,
    result: null,
    error: null
  });

  const handleFileSelect = (file: File) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      setState(prev => ({
        ...prev,
        file,
        preview: reader.result as string,
        error: null,
        result: null
      }));
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!state.preview || !state.file) return;

    setState(prev => ({ ...prev, isAnalyzing: true, error: null }));

    try {
      const base64Data = state.preview.split(',')[1];
      const mimeType = state.file.type;

      const analysisResult = await analyzeMedicalDocument(base64Data, mimeType);

      setState(prev => ({
        ...prev,
        isAnalyzing: false,
        result: analysisResult
      }));
    } catch (err: any) {
      console.error(err);
      setState(prev => ({
        ...prev,
        isAnalyzing: false,
        error: "Failed to analyze document. Please ensure the image is clear and try again."
      }));
    }
  };

  const clearFile = () => {
    setState({
      file: null,
      preview: null,
      isAnalyzing: false,
      result: null,
      error: null
    });
  };

  return (
    <Layout>
      <div className="max-w-4xl mx-auto px-4 py-12 sm:px-6 lg:px-8">
        {/* Intro */}
        {!state.result && !state.isAnalyzing && (
          <div className="text-center mb-12">
            <h1 className="text-4xl md:text-5xl font-extrabold text-slate-900 tracking-tight mb-4">
              Demystify your <span className="text-blue-600">Medical Bills</span> & <span className="text-emerald-600">Prescriptions</span>
            </h1>
            <p className="text-xl text-slate-600 max-w-2xl mx-auto">
              Securely analyze hospital bills for hidden charges and translate complex medical jargon into simple Indian-English.
            </p>
          </div>
        )}

        {/* Upload Section */}
        {!state.result && !state.isAnalyzing && (
          <div className="space-y-8">
            <FileUploader 
              onFileSelect={handleFileSelect} 
              selectedFile={state.file}
              onClear={clearFile}
            />

            {state.file && (
              <div className="flex justify-center">
                <button
                  onClick={handleAnalyze}
                  className="bg-blue-600 text-white px-8 py-4 rounded-2xl font-bold text-lg hover:bg-blue-700 transition-all shadow-lg hover:shadow-blue-200 active:scale-95 flex items-center space-x-3"
                >
                  <Sparkles className="w-5 h-5" />
                  <span>Simplify Document</span>
                </button>
              </div>
            )}

            {/* Features Row */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pt-12">
              <div className="p-6 bg-white rounded-3xl border border-slate-200">
                <div className="w-10 h-10 bg-blue-100 rounded-xl flex items-center justify-center mb-4">
                  <FileText className="w-5 h-5 text-blue-600" />
                </div>
                <h3 className="font-bold text-slate-900 mb-2">Prescription Decoding</h3>
                <p className="text-sm text-slate-500">Explains medicines, dosages, and what tests are for in plain language.</p>
              </div>
              <div className="p-6 bg-white rounded-3xl border border-slate-200">
                <div className="w-10 h-10 bg-amber-100 rounded-xl flex items-center justify-center mb-4">
                  <AlertCircle className="w-5 h-5 text-amber-600" />
                </div>
                <h3 className="font-bold text-slate-900 mb-2">Billing Guard</h3>
                <p className="text-sm text-slate-500">Flags potential overcharges or consumables often wrongly billed to patients.</p>
              </div>
              <div className="p-6 bg-white rounded-3xl border border-slate-200">
                <div className="w-10 h-10 bg-emerald-100 rounded-xl flex items-center justify-center mb-4">
                  <CheckCircle className="w-5 h-5 text-emerald-600" />
                </div>
                <h3 className="font-bold text-slate-900 mb-2">Claim Support</h3>
                <p className="text-sm text-slate-500">Helps you understand why an insurance claim was rejected and how to appeal.</p>
              </div>
            </div>
          </div>
        )}

        {/* Loading State */}
        {state.isAnalyzing && (
          <div className="flex flex-col items-center justify-center py-20 space-y-6">
            <div className="relative">
              <Loader2 className="w-16 h-16 text-blue-600 animate-spin" />
              <div className="absolute inset-0 flex items-center justify-center">
                <Sparkles className="w-6 h-6 text-blue-400 animate-pulse" />
              </div>
            </div>
            <div className="text-center">
              <h2 className="text-2xl font-bold text-slate-800">SevaMed AI is analyzing...</h2>
              <p className="text-slate-500 mt-2">Reading document, checking codes, and simplifying jargon.</p>
            </div>
            <div className="max-w-xs w-full bg-slate-100 rounded-full h-1.5 mt-8 overflow-hidden">
              <div className="bg-blue-600 h-full animate-progress-indefinite w-1/3 rounded-full"></div>
            </div>
          </div>
        )}

        {/* Results View */}
        {state.result && (
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <button 
                onClick={clearFile}
                className="text-slate-500 hover:text-blue-600 font-medium flex items-center space-x-2"
              >
                <span>&larr; Analyze another document</span>
              </button>
            </div>
            <AnalysisView analysis={state.result} />
          </div>
        )}

        {/* Error State */}
        {state.error && (
          <div className="bg-red-50 border border-red-200 rounded-2xl p-6 text-center mt-12">
            <AlertCircle className="w-12 h-12 text-red-500 mx-auto mb-4" />
            <h3 className="text-lg font-bold text-red-900">Analysis Error</h3>
            <p className="text-red-700 mt-2">{state.error}</p>
            <button 
              onClick={clearFile}
              className="mt-6 px-6 py-2 bg-red-600 text-white rounded-xl font-bold hover:bg-red-700 transition-colors"
            >
              Try Again
            </button>
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;

export enum DocumentType {
  PRESCRIPTION = 'PRESCRIPTION',
  LAB_REPORT = 'LAB_REPORT',
  HOSPITAL_BILL = 'HOSPITAL_BILL',
  INSURANCE_REJECTION = 'INSURANCE_REJECTION',
  UNKNOWN = 'UNKNOWN'
}

export interface MedicalAnalysis {
  id?: string;
  timestamp?: number;
  documentType: DocumentType;
  summary: string;
  simplifiedTerms: {
    jargon: string;
    meaning: string;
    importance: string;
  }[];
  criticalFindings: {
    issue: string;
    description: string;
    action: string;
  }[];
  billAnalysis?: {
    totalAmount: string;
    potentialOvercharges: {
      item: string;
      reason: string;
      suggestedAction: string;
    }[];
  };
  insuranceInsights?: {
    rejectionReason?: string;
    appealAdvice?: string;
  };
  nextSteps: string[];
}

export interface User {
  id: string;
  name: string;
  email: string;
}

export interface AnalysisState {
  file: File | null;
  preview: string | null;
  isAnalyzing: boolean;
  result: MedicalAnalysis | null;
  error: string | null;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
}

import React, { useState } from 'react';
import { Mail, Lock, User, Loader2, ArrowRight } from 'lucide-react';

interface AuthFormsProps {
  type: 'login' | 'signup';
  onSubmit: (data: any) => Promise<void>;
  onSwitch: () => void;
}

export const AuthForms: React.FC<AuthFormsProps> = ({ type, onSubmit, onSwitch }) => {
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
