import React, { useState, useEffect, useCallback } from 'react';
import { Layout } from './components/Layout';
import { LandingPage } from './components/LandingPage';
import { AuthForms } from './components/AuthForms';
import { FileUploader } from './components/FileUploader';
import { AnalysisView } from './components/AnalysisView';
import { analyzeMedicalDocument } from './services/geminiService';
import { AnalysisState, User, MedicalAnalysis } from './types';
import { Loader2, AlertCircle, FileText, CheckCircle, Sparkles, History, Search } from 'lucide-react';

const App: React.FC = () => {
  // --- Auth State ---
  const [user, setUser] = useState<User | null>(null);
  const [authView, setAuthView] = useState<'landing' | 'login' | 'signup'>('landing');
  const [isAuthLoading, setIsAuthLoading] = useState(true);

  // --- Analysis State ---
  const [state, setState] = useState<AnalysisState>({
    file: null,
    preview: null,
    isAnalyzing: false,
    result: null,
    error: null
  });

  const [history, setHistory] = useState<MedicalAnalysis[]>([]);

  // --- Initialization ---
  useEffect(() => {
    // Check localStorage for session
    const storedUser = localStorage.getItem('sevamed_user');
    if (storedUser) {
      const parsedUser = JSON.parse(storedUser);
      setUser(parsedUser);
      loadHistory(parsedUser.id);
    }
    setIsAuthLoading(false);
  }, []);

  const loadHistory = (userId: string) => {
    const storedHistory = localStorage.getItem(`sevamed_history_${userId}`);
    if (storedHistory) {
      setHistory(JSON.parse(storedHistory));
    }
  };

  const saveToHistory = (analysis: MedicalAnalysis) => {
    if (!user) return;
    const newAnalysis = {
      ...analysis,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };
    const updatedHistory = [newAnalysis, ...history];
    setHistory(updatedHistory);
    localStorage.setItem(`sevamed_history_${user.id}`, JSON.stringify(updatedHistory));
  };

  // --- Auth Handlers ---
  const handleAuth = async (data: any) => {
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 800));
    const mockUser: User = {
      id: data.id || 'usr_' + Math.random().toString(36).substr(2, 5),
      name: data.name || data.email.split('@')[0],
      email: data.email
    };
    setUser(mockUser);
    localStorage.setItem('sevamed_user', JSON.stringify(mockUser));
    loadHistory(mockUser.id);
    setAuthView('landing');
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('sevamed_user');
    setHistory([]);
    setAuthView('landing');
    clearFile();
  };

  // --- Analysis Handlers ---
  const handleFileSelect = (file: File) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      setState(prev => ({
        ...prev,
        file,
        preview: reader.result as string,
        error: null,
        result: null
      }));
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!state.preview || !state.file) return;

    setState(prev => ({ ...prev, isAnalyzing: true, error: null }));

    try {
      const base64Data = state.preview.split(',')[1];
      const mimeType = state.file.type;

      const analysisResult = await analyzeMedicalDocument(base64Data, mimeType);

      setState(prev => ({
        ...prev,
        isAnalyzing: false,
        result: analysisResult
      }));

      saveToHistory(analysisResult);
    } catch (err: any) {
      console.error(err);
      setState(prev => ({
        ...prev,
        isAnalyzing: false,
        error: "Failed to analyze document. Please ensure the image is clear and try again."
      }));
    }
  };

  const clearFile = () => {
    setState({
      file: null,
      preview: null,
      isAnalyzing: false,
      result: null,
      error: null
    });
  };

  const selectHistoryItem = (item: MedicalAnalysis) => {
    setState(prev => ({
      ...prev,
      result: item,
      file: null,
      preview: null
    }));
  };

  // --- Render logic ---

  if (isAuthLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <Loader2 className="w-12 h-12 text-blue-600 animate-spin" />
      </div>
    );
  }

  // Show Auth Forms
  if (authView === 'login' || authView === 'signup') {
    return (
      <Layout user={user} onLogout={handleLogout} onLoginClick={() => setAuthView('login')}>
        <div className="py-20 bg-slate-50 min-h-[80vh] flex items-center justify-center px-4">
          <AuthForms 
            type={authView} 
            onSubmit={handleAuth} 
            onSwitch={() => setAuthView(authView === 'login' ? 'signup' : 'login')} 
          />
        </div>
      </Layout>
    );
  }

  // Show Landing Page for unauthenticated users
  if (!user) {
    return (
      <Layout user={null} onLogout={handleLogout} onLoginClick={() => setAuthView('login')} showLanding>
        <LandingPage onGetStarted={() => setAuthView('signup')} />
      </Layout>
    );
  }

  // Authenticated Dashboard
  return (
    <Layout user={user} onLogout={handleLogout}>
      <div className="max-w-6xl mx-auto px-4 py-12 sm:px-6 lg:px-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">

          {/* Left Sidebar: Recent History */}
          <div className="lg:col-span-4 space-y-8">
            <div className="bg-white border border-slate-200 rounded-[2rem] p-6 shadow-sm">
              <div className="flex items-center justify-between mb-6">
                <h3 className="text-lg font-bold text-slate-900 flex items-center">
                  <History className="w-5 h-5 mr-2 text-blue-600" />
                  Your History
                </h3>
              </div>

              <div className="space-y-3 overflow-y-auto max-h-[500px] pr-2 custom-scrollbar">
                {history.length > 0 ? history.map((item) => (
                  <button
                    key={item.id}
                    onClick={() => selectHistoryItem(item)}
                    className={`w-full text-left p-4 rounded-2xl border transition-all ${
                      state.result?.id === item.id 
                        ? 'border-blue-200 bg-blue-50 ring-2 ring-blue-100' 
                        : 'border-slate-100 bg-slate-50 hover:bg-slate-100'
                    }`}
                  >
                    <p className="text-xs font-bold text-blue-600 uppercase mb-1">{item.documentType.replace('_', ' ')}</p>
                    <p className="text-sm font-semibold text-slate-800 line-clamp-1">{item.summary}</p>
                    <p className="text-[10px] text-slate-400 mt-2">
                      {item.timestamp ? new Date(item.timestamp).toLocaleDateString() : 'Recently'}
                    </p>
                  </button>
                )) : (
                  <div className="text-center py-12 px-4 border-2 border-dashed border-slate-100 rounded-2xl">
                    <p className="text-sm text-slate-400">No documents analyzed yet.</p>
                  </div>
                )}
              </div>
            </div>

            <div className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-[2rem] p-6 text-white shadow-lg">
              <h4 className="font-bold mb-2">Need help?</h4>
              <p className="text-sm text-blue-100 opacity-90 mb-4">Our expert support is here for any queries about your billing flags.</p>
              <button className="w-full py-3 bg-white/20 hover:bg-white/30 rounded-xl text-sm font-bold transition-colors">
                Contact Advisor
              </button>
            </div>
          </div>

          {/* Main Content: Analyzer / Result */}
          <div className="lg:col-span-8">
            {state.isAnalyzing ? (
              <div className="flex flex-col items-center justify-center py-20 space-y-6 bg-white border border-slate-200 rounded-[3rem] shadow-sm">
                <div className="relative">
                  <div className="absolute inset-0 bg-blue-100 rounded-full animate-ping opacity-25"></div>
                  <Loader2 className="w-16 h-16 text-blue-600 animate-spin relative z-10" />
                </div>
                <div className="text-center">
                  <h2 className="text-2xl font-bold text-slate-800">Processing Document</h2>
                  <p className="text-slate-500 mt-2">SevaMed AI is analyzing handwriting, medical codes, and bill items.</p>
                </div>
              </div>
            ) : state.result ? (
              <div className="space-y-6">
                <div className="flex items-center justify-between">
                  <button 
                    onClick={clearFile}
                    className="px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 font-bold rounded-xl flex items-center space-x-2 transition-all"
                  >
                    <span>&larr; New Analysis</span>
                  </button>
                </div>
                <AnalysisView analysis={state.result} />
              </div>
            ) : (
              <div className="bg-white border border-slate-200 rounded-[3rem] p-10 shadow-sm text-center">
                <div className="max-w-md mx-auto">
                  <div className="w-20 h-20 bg-blue-50 rounded-[2rem] flex items-center justify-center mx-auto mb-8">
                    <Sparkles className="w-10 h-10 text-blue-600" />
                  </div>
                  <h2 className="text-3xl font-bold text-slate-900 mb-4">Analyze Medical Document</h2>
                  <p className="text-slate-600 mb-10">
                    Upload your prescription, lab report or hospital bill for an instant plain-language explanation.
                  </p>

                  <FileUploader 
                    onFileSelect={handleFileSelect} 
                    selectedFile={state.file}
                    onClear={clearFile}
                  />

                  {state.file && (
                    <button
                      onClick={handleAnalyze}
                      className="w-full mt-8 bg-blue-600 text-white py-4 rounded-2xl font-bold text-lg hover:bg-blue-700 transition-all shadow-xl shadow-blue-100 flex items-center justify-center space-x-3"
                    >
                      <Sparkles className="w-5 h-5" />
                      <span>Start Analysis</span>
                    </button>
                  )}

                  {state.error && (
                    <div className="mt-6 flex items-center justify-center space-x-2 text-red-600 bg-red-50 p-4 rounded-2xl">
                      <AlertCircle className="w-5 h-5" />
                      <p className="text-sm font-bold">{state.error}</p>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
};

export default App;

