      email: 'aditya.sharma@example.com'
    };
    persistUser(googleUser);
  };

  const persistUser = (userData: User) => {
    setUser(userData);
    localStorage.setItem('sevamed_user', JSON.stringify(userData));
    loadHistory(userData.id);
    setAuthView('landing');
  };

