const App: React.FC = () => {
  // --- Auth State ---
  const [user, setUser] = useState<User | null>(null);
  const [authView, setAuthView] = useState<'landing' | 'login' | 'signup'>('landing');
  const [isAuthLoading, setIsAuthLoading] = useState(true);

  // --- Analysis State ---
  const [state, setState] = useState<AnalysisState>({
    file: null,
    preview: null,
    isAnalyzing: false,
    result: null,
    error: null
  });

  const [history, setHistory] = useState<MedicalAnalysis[]>([]);

  // --- Persistent Session Logic ---
  useEffect(() => {
    const checkSession = () => {
      try {
        const storedUser = localStorage.getItem('sevamed_user');
        if (storedUser) {
          const parsedUser = JSON.parse(storedUser);
          if (parsedUser && parsedUser.id && parsedUser.email) {
            setUser(parsedUser);
            loadHistory(parsedUser.id);
          }
        }
      } catch (err) {
        console.error("Session restoration failed:", err);
        localStorage.removeItem('sevamed_user');
      } finally {
        setIsAuthLoading(false);
      }
    };

    checkSession();
  }, []);

  const loadHistory = (userId: string) => {
    const storedHistory = localStorage.getItem(`sevamed_history_${userId}`);
    if (storedHistory) {
      try {
        setHistory(JSON.parse(storedHistory));
      } catch (e) {
        console.error("Failed to parse history");
        setHistory([]);
      }
    }
  };

  const saveToHistory = (analysis: MedicalAnalysis) => {
    if (!user) return;
    const newAnalysis = {
      ...analysis,
      id: analysis.id || Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };
    const updatedHistory = [newAnalysis, ...history];
    setHistory(updatedHistory);
    localStorage.setItem(`sevamed_history_${user.id}`, JSON.stringify(updatedHistory));
  };

  // --- Auth Handlers ---
  const handleAuth = async (data: any) => {
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 800));
    const mockUser: User = {
      id: 'usr_' + Math.random().toString(36).substr(2, 9),
      name: data.name || data.email.split('@')[0],
      email: data.email
    };
    persistUser(mockUser);
  };

  const handleGoogleLogin = async () => {
    // Simulate Google OAuth Redirect/Popup flow
    await new Promise(resolve => setTimeout(resolve, 1500));
    const googleUser: User = {
      id: 'goog_' + Math.random().toString(36).substr(2, 9),
      name: 'Patient User',
      email: 'user@example.com'
    };
    persistUser(googleUser);
  };

  const persistUser = (userData: User) => {
    setUser(userData);
