    loadHistory(userData.id);
    setAuthView('landing');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('sevamed_user');
    setHistory([]);
    setAuthView('landing');
    clearFile();
  };

  // --- Analysis Handlers ---
  const handleFileSelect = (file: File) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      setState(prev => ({
        ...prev,
        file,
        preview: reader.result as string,
        error: null,
        result: null
      }));
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!state.preview || !state.file) return;

    setState(prev => ({ ...prev, isAnalyzing: true, error: null }));

    try {
      const base64Data = state.preview.split(',')[1];
      const mimeType = state.file.type;

      const analysisResult = await analyzeMedicalDocument(base64Data, mimeType);

      setState(prev => ({
        ...prev,
        isAnalyzing: false,
        result: analysisResult
      }));

      saveToHistory(analysisResult);
    } catch (err: any) {
      console.error(err);
      setState(prev => ({
        ...prev,
        isAnalyzing: false,
        error: "Failed to analyze document. Please ensure the image is clear and try again."
      }));
    }
  };

  const clearFile = () => {
    setState({
      file: null,
      preview: null,
      isAnalyzing: false,
      result: null,
      error: null
    });
  };

  const selectHistoryItem = (item: MedicalAnalysis) => {
    setState(prev => ({
      ...prev,
      result: item,
      file: null,
      preview: null,
      error: null
    }));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

