                <h3 className="text-lg font-bold text-slate-900 flex items-center">
                  <History className="w-5 h-5 mr-2 text-blue-600" />
                  Your History
                </h3>
              </div>

              <div className="space-y-3 overflow-y-auto max-h-[500px] pr-2 custom-scrollbar">
                {history.length > 0 ? history.map((item) => (
                  <button
                    key={item.id}
                    onClick={() => selectHistoryItem(item)}
                    className={`w-full text-left p-4 rounded-2xl border transition-all ${
                      state.result?.id === item.id 
                        ? 'border-blue-200 bg-blue-50 ring-2 ring-blue-100 shadow-sm' 
                        : 'border-slate-100 bg-slate-50 hover:bg-slate-100'
                    }`}
                  >
                    <p className="text-xs font-bold text-blue-600 uppercase mb-1">{item.documentType.replace('_', ' ')}</p>
                    <p className="text-sm font-semibold text-slate-800 line-clamp-1">{item.summary}</p>
                    <p className="text-[10px] text-slate-400 mt-2">
                      {item.timestamp ? new Date(item.timestamp).toLocaleDateString() : 'Recently'}
                    </p>
                  </button>
                )) : (
                  <div className="text-center py-12 px-4 border-2 border-dashed border-slate-100 rounded-2xl">
                    <p className="text-sm text-slate-400">No documents analyzed yet.</p>
                  </div>
                )}
              </div>
            </div>

            <div className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-[2rem] p-6 text-white shadow-lg">
              <h4 className="font-bold mb-2 text-lg">Need Advisor Help?</h4>
              <p className="text-sm text-blue-100 opacity-90 mb-4">Our healthcare billing experts can review flagged charges with you directly.</p>
              <button 
                onClick={() => alert("Advisor service coming soon to SevaMed Pro!")}
                className="w-full py-3 bg-white/20 hover:bg-white/30 rounded-xl text-sm font-bold transition-colors"
              >
                Contact Advisor
              </button>
            </div>
          </div>

          {/* Main Content: Analyzer / Result */}
          <div className="lg:col-span-8">
            {state.isAnalyzing ? (
              <div className="flex flex-col items-center justify-center py-20 space-y-6 bg-white border border-slate-200 rounded-[3rem] shadow-sm">
                <div className="relative">
                  <div className="absolute inset-0 bg-blue-100 rounded-full animate-ping opacity-25"></div>
