      <div className="py-20 flex justify-center px-4">
        <AuthForms type={authView as any} onSubmit={async(d)=>{setUser({id:'1',...d}); localStorage.setItem('sevamed_user',JSON.stringify({id:'1',...d})); setAuthView('landing')}} onGoogleLogin={async()=>{}} onSwitch={()=>setAuthView(authView==='login'?'signup':'login')} />
      </div>
    </Layout>
  );
  if (!user) return <Layout user={null} onLogout={()=>{}} onLoginClick={()=>setAuthView('login')} showLanding><LandingPage onGetStarted={()=>setAuthView('signup')} /></Layout>;

