const express = require('express');
const { GoogleGenAI } = require("@google/genai");
const axios = require('axios');

const app = express();
app.use(express.urlencoded({ extended: false }));

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

app.post('/whatsapp-webhook', async (req, res) => {
  const from = req.body.From;
  const mediaUrl = req.body.MediaUrl0;

  if (!mediaUrl) {
    return res.status(200).send('No media detected.');
  }

  try {
    // 1. Download image from WhatsApp
    const imageResponse = await axios.get(mediaUrl, { responseType: 'arraybuffer' });
    const base64Image = Buffer.from(imageResponse.data).toString('base64');

    // 2. Call Gemini for WhatsApp-optimized summary
    const model = ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
          { text: "Analyze this medical document. Provide a short WhatsApp message (max 500 chars) explaining: 1. What it is. 2. Jargon explained simply. 3. Cheaper generic medicines if prescription. 4. Overcharge warning if bill. Use Emojis." }
        ]
      }
    });

    const aiResponse = await model;
    const messageText = aiResponse.text;

    // 3. Send response back to user via Twilio
    // twilioClient.messages.create({ from: 'whatsapp:+14155238886', to: from, body: messageText });

    res.status(200).send('Processed');
  } catch (error) {
    console.error('WhatsApp Process Error:', error);
    res.status(200).send('Error');
  }
});

module.exports = app;

import { GoogleGenAI, Type } from "@google/genai";
import { DocumentType, MedicalAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const ANALYSIS_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    documentType: { type: Type.STRING },
    summary: { type: Type.STRING },
    simplifiedTerms: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          jargon: { type: Type.STRING },
          meaning: { type: Type.STRING },
          importance: { type: Type.STRING }
        }
      }
    },
    criticalFindings: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          issue: { type: Type.STRING },
          description: { type: Type.STRING },
          action: { type: Type.STRING }
        }
      }
    },
    genericAlternatives: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          brandedName: { type: Type.STRING },
          genericName: { type: Type.STRING },
          approxBrandedPrice: { type: Type.STRING },
          approxGenericPrice: { type: Type.STRING },
          savingsPercentage: { type: Type.STRING }
        }
      }
    },
    costInsights: {
      type: Type.OBJECT,
      properties: {
        procedureName: { type: Type.STRING },
        billedAmount: { type: Type.STRING },
        expectedRange: {
          type: Type.OBJECT,
          properties: {
            privateLow: { type: Type.STRING },
            privateHigh: { type: Type.STRING },
            government: { type: Type.STRING }
          }
        },
        isOvercharged: { type: Type.BOOLEAN },
        tierComparison: { type: Type.STRING }
      },
      required: ['procedureName', 'expectedRange', 'isOvercharged', 'tierComparison']
    },
    billAnalysis: {
      type: Type.OBJECT,
      properties: {
        totalAmount: { type: Type.STRING },
        potentialOvercharges: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              item: { type: Type.STRING },
              reason: { type: Type.STRING },
              suggestedAction: { type: Type.STRING }
            }
          }
        }
      }
    },
    insuranceInsights: {
      type: Type.OBJECT,
      properties: {
        rejectionReason: { type: Type.STRING },
        appealAdvice: { type: Type.STRING }
      }
    },
    nextSteps: { type: Type.ARRAY, items: { type: Type.STRING } }
  },
  required: ['documentType', 'summary', 'simplifiedTerms', 'criticalFindings', 'nextSteps']
};

export const analyzeMedicalDocument = async (
  base64Data: string,
  mimeType: string,
  cityTier: string = 'Tier-1'
): Promise<MedicalAnalysis> => {
  // Always use the latest flash model for general document analysis
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            data: base64Data,
            mimeType: mimeType
          }
        },
        {
          text: `You are an expert Indian Medical Consultant. 
          Context: Patient is in a ${cityTier} city in India.
          Analyze this medical document. 
          1. Determine Document Type (Prescription, Bill, Lab, Insurance Rejection).
          2. Explain medical jargon in simple English.
          3. If Prescription: Identify BRANDED medicines and suggest Jan Aushadhi (Generic) alternatives with estimated price difference in INR (₹).
          4. If Bill: Benchmark costs against Indian averages for ${cityTier}. 
             Standard surgery ranges for reference: Cataract ₹20k-40k, C-Section ₹60k-1L, Dialysis ₹2.5k-5k.
          5. Flag any unusually high charges or unnecessary "miscellaneous" fees.
          6. Recommend actionable next steps (e.g., 'Consult for Generic switch', 'Appeal Insurance').

          ALWAYS add a clear disclaimer: 'Consult your doctor before making changes to medication.'
          Format output strictly as JSON according to the provided schema.`
        }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: ANALYSIS_SCHEMA as any,
    }
  });

  const text = response.text;
  if (!text) {
    throw new Error("No analysis generated from the model.");
  }

  try {
    return JSON.parse(text) as MedicalAnalysis;
  } catch (e) {
    console.error("Failed to parse Gemini response as JSON:", text);
    throw new Error("Invalid analysis format received from AI.");
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Layout } from './components/Layout';
import { LandingPage } from './components/LandingPage';
import { AuthForms } from './components/AuthForms';
import { FileUploader } from './components/FileUploader';
import { AnalysisView } from './components/AnalysisView';
import { analyzeMedicalDocument } from './services/geminiService';
import { AnalysisState, User, MedicalAnalysis } from './types';
import { Loader2, AlertCircle, Sparkles, History, MapPin } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [cityTier, setCityTier] = useState<'Tier-1' | 'Tier-2' | 'Tier-3'>('Tier-1');
  const [authView, setAuthView] = useState<'landing' | 'login' | 'signup'>('landing');
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [state, setState] = useState<AnalysisState>({
    file: null, 
    preview: null, 
    isAnalyzing: false, 
    result: null, 
    error: null
  });
  const [history, setHistory] = useState<MedicalAnalysis[]>([]);

  // Persistent session logic
  useEffect(() => {
    const initApp = () => {
      try {
        const storedUser = localStorage.getItem('prescription_user');
        if (storedUser) {
          const parsedUser = JSON.parse(storedUser);
          if (parsedUser && parsedUser.id) {
            setUser(parsedUser);
            const storedHistory = localStorage.getItem(`prescription_history_${parsedUser.id}`);
            if (storedHistory) {
              setHistory(JSON.parse(storedHistory));
            }
          }
        }
      } catch (err) {
        console.error("Auth initialization error:", err);
      } finally {
        setIsAuthLoading(false);
      }
    };
    initApp();
  }, []);

  const handleAuthSubmit = async (data: any) => {
    // Simulate auth
    const newUser: User = { 
      id: Math.random().toString(36).substr(2, 9), 
      name: data.name || data.email.split('@')[0], 
      email: data.email,
      cityTier: cityTier
    };
    setUser(newUser);
    localStorage.setItem('prescription_user', JSON.stringify(newUser));
    setAuthView('landing');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('prescription_user');
    setHistory([]);
    setAuthView('landing');
    clearFile();
  };

  const clearFile = () => {
    setState({
      file: null,
      preview: null,
      isAnalyzing: false,
      result: null,
      error: null
    });
  };

  const handleFileSelect = (file: File) => {
    const reader = new FileReader();
    reader.onload = () => {
      setState(prev => ({
        ...prev,
        file,
        preview: reader.result as string,
        error: null,
        result: null
      }));
    };
    reader.readAsDataURL(file);
  };

  const handleAnalyze = async () => {
    if (!state.preview || !state.file) return;

    setState(prev => ({ ...prev, isAnalyzing: true, error: null }));

    try {
      const base64Data = state.preview.split(',')[1];
      const mimeType = state.file.type;
      const analysisResult = await analyzeMedicalDocument(base64Data, mimeType, cityTier);

      const enrichedResult = {
        ...analysisResult,
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now()
      };

      setState(prev => ({ ...prev, isAnalyzing: false, result: enrichedResult }));

      if (user) {
        const updatedHistory = [enrichedResult, ...history];
        setHistory(updatedHistory);
        localStorage.setItem(`prescription_history_${user.id}`, JSON.stringify(updatedHistory));
      }
    } catch (err: any) {
      console.error("Analysis Error:", err);
      setState(prev => ({ 
        ...prev, 
        isAnalyzing: false, 
        error: "We couldn't analyze the document. Please ensure the image is clear and try again." 
      }));
    }
  };

  const goHome = useCallback(() => {
    if (!user) {
      setAuthView('landing');
    } else {
      clearFile();
    }
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [user]);

  if (isAuthLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600" />
      </div>
    );
  }

  if (!user && authView !== 'landing') {
    return (
      <Layout 
        user={null} 
        onLogout={() => {}} 
        onLoginClick={() => setAuthView('login')}
        onLogoClick={goHome}
      >
        <div className="py-20 flex justify-center px-4">
          <AuthForms 
            type={authView as any} 
            onSubmit={handleAuthSubmit} 
            onGoogleLogin={async () => {}} 
            onSwitch={() => setAuthView(authView === 'login' ? 'signup' : 'login')} 
          />
        </div>
      </Layout>
    );
  }

  if (!user) {
    return (
      <Layout 
        user={null} 
        onLogout={handleLogout} 
        onLoginClick={() => setAuthView('login')} 
        onLogoClick={goHome}
        showLanding
      >
        <LandingPage onGetStarted={() => setAuthView('signup')} />
      </Layout>
    );
  }

  return (
    <Layout user={user} onLogout={handleLogout} onLogoClick={goHome}>
      <div className="max-w-6xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          {/* Sidebar */}
          <div className="lg:col-span-4 space-y-6 no-print">
             <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm">
               <h3 className="font-bold text-slate-800 mb-4 flex items-center">
                 <MapPin className="w-5 h-5 mr-2 text-blue-600" /> Location Context
               </h3>
               <select 
                 value={cityTier} 
                 onChange={(e) => setCityTier(e.target.value as any)}
                 className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl font-semibold text-slate-700 outline-none focus:ring-2 focus:ring-blue-500 transition-all cursor-pointer"
               >
                 <option value="Tier-1">Metro / Tier 1 (Mumbai, Delhi, BLR)</option>
                 <option value="Tier-2">Tier 2 (Pune, Jaipur, Lucknow)</option>
                 <option value="Tier-3">Tier 3 / Rural Cities</option>
               </select>
               <p className="text-[10px] text-slate-400 mt-2 italic">*Benchmarks adjust based on standard city living costs.</p>
             </div>

             <div className="bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm">
               <h3 className="font-bold text-slate-800 mb-4 flex items-center">
                 <History className="w-5 h-5 mr-2 text-blue-600" /> Recent History
               </h3>
               <div className="space-y-3 max-h-[400px] overflow-y-auto custom-scrollbar pr-2">
                 {history.length > 0 ? history.map(h => (
                   <button 
                     key={h.id} 
                     onClick={() => setState(prev => ({ ...prev, result: h }))} 
                     className={`w-full text-left p-3 rounded-xl transition-all border ${state.result?.id === h.id ? 'bg-blue-50 border-blue-200' : 'bg-slate-50 border-transparent hover:border-slate-200'}`}
                   >
                     <p className="text-[10px] font-bold text-blue-600 uppercase tracking-tighter">{h.documentType.replace('_', ' ')}</p>
                     <p className="text-sm font-semibold truncate text-slate-800">{h.summary}</p>
                     <p className="text-[9px] text-slate-400 mt-1">{h.timestamp ? new Date(h.timestamp).toLocaleDateString() : 'Recent'}</p>
                   </button>
                 )) : (
                   <p className="text-sm text-slate-400 py-4 text-center">No previous scans found.</p>
                 )}
               </div>
             </div>
          </div>

          {/* Analyzer Area */}
          <div className="lg:col-span-8">
