                  <Sparkles className="w-5 h-5" /> <span>Analyze Now</span>
                </button>
              )}
              {state.error && <div className="mt-4 text-red-600 bg-red-50 p-3 rounded-xl border border-red-100 text-sm font-bold">{state.error}</div>}
            </div>
          )}
        </main>
      </div>
    </Layout>
  );
};

